<?php
namespace App\Services\Finance;
use App\Data\Payments\PaymentProviderResult; use App\Models\{Order,PaymentRecord,PaymentWebhookEvent,User}; use Illuminate\Support\Str;
class PaymentService{public function __construct(private PaymentProviderManager $providers,private PaymentNumberGenerator $numbers){} public function createDraftPaymentForOrder(Order $o,User $a):PaymentRecord{$q=$o->latestPriceQuote();$p=PaymentRecord::create(['payment_number'=>$this->numbers->payment(),'order_id'=>$o->id,'customer_id'=>$o->customer_id,'provider'=>$this->providers->provider()->providerKey(),'status'=>'draft','currency'=>$q?->currency??$o->currency,'amount'=>$q?->total,'idempotency_key'=>(string)Str::uuid(),'requested_by_id'=>$a->id]);$this->event($p,$a,'created','Draft payment record created.');return $p;} public function requestPaymentIntent(PaymentRecord $p,User $a):PaymentProviderResult{return $this->blocked($p,$a,'intent_requested',$this->providers->provider()->createPaymentIntent($p));} public function capturePayment(PaymentRecord $p,User $a):PaymentProviderResult{return $this->blocked($p,$a,'capture_requested',$this->providers->provider()->capture($p));} public function refundPayment(PaymentRecord $p,User $a,string $amount,string $reason):PaymentProviderResult{return $this->blocked($p,$a,'refund_requested',$this->providers->provider()->refund($p,$amount,$reason));} public function recordWebhook(string $provider,array $payload,array $headers):PaymentWebhookEvent{$hash=hash('sha256',json_encode($payload,JSON_THROW_ON_ERROR));if($e=PaymentWebhookEvent::where('provider',$provider)->where('payload_hash',$hash)->first()){$e->update(['status'=>'ignored','failure_reason'=>'Duplicate unverified webhook ignored.']);return $e;}return PaymentWebhookEvent::create(['provider'=>$provider,'provider_event_id'=>$payload['id']??$payload['reference']??null,'event_type'=>$payload['name']??null,'payload_hash'=>$hash,'status'=>'rejected','received_at'=>now(),'failure_reason'=>'Webhook rejected because signature verification is not configured.','metadata'=>['verification'=>'fail_closed']]);} private function blocked(PaymentRecord $p,User $a,string $requested,PaymentProviderResult $r):PaymentProviderResult{if(!$r->successful){$p->update(['status'=>'provider_disabled','failure_reason'=>$r->message]);$this->event($p,$a,'provider_not_configured',$r->message,['requested_action'=>$requested]);}return $r;} private function event(PaymentRecord $p,User $a,string $type,string $description,array $metadata=[]):void{$p->events()->create(['order_id'=>$p->order_id,'actor_id'=>$a->id,'event_type'=>$type,'provider'=>$p->provider,'idempotency_key'=>$p->idempotency_key,'description'=>$description,'metadata'=>$metadata,'created_at'=>now()]);}}